import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
  input,
  output,
} from '@angular/core';

/** A smart component that emits a selection event when activated. */
@Component({
  selector: 'smart-ngx-smart-components',
  imports: [],
  template: `<p>{{ label() }} works!</p>`,
  styles: `
    :host {
      display: block;
    }
  `,
  encapsulation: ViewEncapsulation.Emulated,
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class NgxSmartComponents {
  /** The display label shown in the component template. */
  readonly label = input<string>('NgxSmartComponents');

  /** Emits the label value when the component is activated. */
  readonly selected = output<string>();
}

export const Primary: Story = {
  args: {
    label: 'NgxSmartComponents',
  },
};

